#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    char s[105];
    while(T--){
        scanf("%s", s);
        int cnt = 0;
        int i = 0;
        while(s[i]){
            char c = s[i];
            if(c=='a'||c=='e'||c=='i'||c=='o'||c=='u') cnt++;
            i++;
        }
        printf("%d", cnt);
        if(T) printf("\n");
    }
    return 0;
}

