const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(input[idx++].trim(), 10);
let results = [];
for (let t = 0; t < T; t++) {
  const s = (input[idx++] || '').trim();
  let cnt = 0;
  let i = 0;
  while (i < s.length) {
    const ch = s[i];
    if (ch === 'a' || ch === 'e' || ch === 'i' || ch === 'o' || ch === 'u') cnt++;
    i++;
  }
  results.push(String(cnt));
}
console.log(results.join('\n'));
